const analyses = Array.isArray($json) ? $json : [$json];
const tickets = analyses.filter(Boolean);
const totalTickets = tickets.length;
const urgentTickets = tickets.filter((ticket) => ticket.priority === 'urgent' || ticket.escalationRequired);
const negativeTickets = tickets.filter((ticket) => ticket.sentiment === 'negative');
const categories = tickets.reduce((counts, ticket) => {
  const category = ticket.category || 'uncategorized';
  counts[category] = (counts[category] || 0) + 1;
  return counts;
}, {});
const escalationQueue = urgentTickets.map((ticket) => ({
  id: ticket.id,
  customerName: ticket.customerName,
  subject: ticket.subject,
  priority: ticket.priority,
  priorityScore: ticket.priorityScore,
  category: ticket.category,
  reason: ticket.escalationReason,
  nextActions: ticket.nextActions || []
}));
const replyReviewQueue = tickets.filter((ticket) => ticket.replyDraft).map((ticket) => ({
  id: ticket.id,
  subject: ticket.subject,
  priority: ticket.priority,
  category: ticket.category,
  draftSubject: ticket.replyDraft.subject,
  draftBody: ticket.replyDraft.body
}));
const faqCandidates = tickets.filter((ticket) => ticket.faqCandidate).map((ticket) => ({
  id: ticket.id,
  question: ticket.faqCandidate.question,
  answerOutline: ticket.faqCandidate.answerOutline,
  reuseScore: ticket.faqCandidate.reuseScore
}));
const topNextActions = tickets.flatMap((ticket) => ticket.nextActions || []).slice(0, 12);
return [{ json: { totalTickets, urgentCount: urgentTickets.length, negativeCount: negativeTickets.length, categories, escalationQueue, replyReviewQueue, faqCandidates, topNextActions, tickets } }];
